Функция ДебетовыйОборотПоКонтрагенту(Счет, Контрагент) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ
	|	ЕСТЬNULL(СУММА(Движения.Сумма), 0) КАК Сумма
	|ИЗ
	|	РегистрБухгалтерии.Хозрасчетный.ДвиженияССубконто(, , СчетДт = &Счет) КАК Движения
	|ГДЕ
	|	Движения.СубконтоДт1 = &Контрагент
	|	ИЛИ Движения.СубконтоДт2 = &Контрагент";

	Запрос.УстановитьПараметр("Счет", Счет);
	Запрос.УстановитьПараметр("Контрагент", Контрагент);

	Выборка = Запрос.Выполнить().Выбрать();

	Если Выборка.Следующий() Тогда
		Возврат Выборка.Сумма;
	КонецЕсли;

	Возврат 0;

КонецФункции
